const required = [
  'name', 
  'phone_primary', 
  'address_street', 
  'address_city', 
  'address_state', 
  'address_zip',
  'channels'
];

const missing = required.filter(field => !payload[field]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}. Payload recebido: ${JSON.stringify(payload)}`);
}

// Normalize phone (remove non-digits except +)
if (payload.phone_primary) {
  payload.phone_primary = payload.phone_primary.replace(/[^\d+]/g, '');
}

if (payload.phone_whatsapp) {
  payload.phone_whatsapp = payload.phone_whatsapp.replace(/[^\d+]/g, '');
}

// Normalize CEP (remove hyphen)
if (payload.address_zip) {
  payload.address_zip = payload.address_zip.replace('-', '');
}

// Add metadata
payload.processed_at = new Date().toISOString();
payload.sync_id = `sync_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

return [payload];

