const data = $input.all()[0].json;

// Gerar store_number numérico único (hash do external_id)
const hashCode = (str) => {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32bit integer
  }
  return Math.abs(hash);
};

const storeNumber = hashCode(data.external_id || data.id);

return [{
  json: {
    ...data,
    fb_store_number: storeNumber
