const items = $input.all();

const results = items.reduce((acc, item) => {
  const channel = item.json.channel;
  acc[channel] = {
    status: item.json.status,
    statusCode: item.json.status_code,
    message: item.json.message,
    durationMs: item.json.duration_ms
  };
  return acc;
}, {});

// ✅ Aceitar 'success' OU 'sent'
